+namespace DocSummary.Services;
+
+public partial class DocumentSummarizationService
+{
+    private static readonly HashSet<string> StopWords = new(StringComparer.OrdinalIgnoreCase)
+    {
+        "a", "an", "the", "and", "or", "but", "is", "are", "was", "were",
+        "in", "on", "at", "to", "for", "of", "with", "by", "it", "its",
+        "this", "that", "from", "as", "be", "been", "being", "have", "has",
+        "had", "do", "does", "did", "will", "would", "could", "should",
+        "may", "might", "not", "no", "so", "if", "then", "than", "too",
+        "very", "can", "just", "about", "into", "over", "after", "before"
+    };
+
+    /// <summary>
+    /// Produces an extractive summary by scoring sentences based on word frequency
+    /// and returning the top-ranked ones in their original order.
+    /// </summary>
+    public string Summarize(string text, int maxSentences)
+    {
+        var sentences = SplitSentences(text);
+
+        if (sentences.Count <= maxSentences)
+            return string.Join(" ", sentences);
+
+        var wordFrequencies = ComputeWordFrequencies(sentences);
+        var scored = ScoreSentences(sentences, wordFrequencies);
+
+        var topIndices = scored
+            .OrderByDescending(s => s.Score)
+            .Take(maxSentences)
+            .Select(s => s.Index)
+            .Order() // preserve original document order
+            .ToList();
+
+        return string.Join(" ", topIndices.Select(i => sentences[i]));
+    }
+
+    private static List<string> SplitSentences(string text)
+    {
+        return SentenceRegex()
+            .Split(text)
+            .Select(s => s.Trim())
+            .Where(s => s.Length > 0)
+            .ToList();
+    }
+
+    private static Dictionary<string, double> ComputeWordFrequencies(List<string> sentences)
+    {
+        var freq = new Dictionary<string, double>(StringComparer.OrdinalIgnoreCase);
+
+        foreach (var sentence in sentences)
+        {
+            foreach (var word in TokenizeWords(sentence))
+            {
+                if (StopWords.Contains(word) || word.Length < 2)
+                    continue;
+
+                freq.TryGetValue(word, out var count);
+                freq[word] = count + 1;
+            }
+        }
+
+        // Normalize by max frequency
+        if (freq.Count > 0)
+        {
+            var max = freq.Values.Max();
+            foreach (var key in freq.Keys)
+                freq[key] /= max;
+        }
+
+        return freq;
+    }
+
+    private static List<(int Index, double Score)> ScoreSentences(
+        List<string> sentences,
+        Dictionary<string, double> wordFrequencies)
+    {
+        var scored = new List<(int Index, double Score)>();
+
+        for (int i = 0; i < sentences.Count; i++)
+        {
+            double score = TokenizeWords(sentences[i])
+                .Where(w => wordFrequencies.ContainsKey(w))
+                .Sum(w => wordFrequencies[w]);
+
+            scored.Add((i, score));
+        }
+
+        return scored;
+    }
+
+    private static IEnumerable<string> TokenizeWords(string sentence)
+    {
+        return WordRegex().Matches(sentence).Select(m => m.Value);
+    }
